import * as fs from 'fs'
import * as path from 'path'

/**
 * Finds files in the current directory and its parent directories.
 * @param cwd The current working directory.
 * @param expectations The expected file names.
 * @returns An array of file paths that match the expectations.
 */
export function findUp(cwd: string, expectations: string[]): string[] {
    let currentDir = cwd
    while (currentDir !== '/') {
        const dirFiles = fs.readdirSync(currentDir)
        const foundFiles = dirFiles.filter((file) => expectations.includes(file))
        if (foundFiles.length > 0) {
            return foundFiles.map((file) => path.join(currentDir, file))
        }
        currentDir = path.dirname(currentDir)
    }
    return []
}
