import { padify } from './pad'
import { Hex, isHex } from './types'

/**
 * A function to convert Uint8Array to hex string
 * @deprecated use `hexlify` instead
 * @param bytes Uint8Array
 * @returns hex string without 0x prefix, e.g., '0102030405'
 */
export function bytesToHex(bytes: Uint8Array): string {
    return trim0x(hexlify(bytes)).replace(/^0x/i, '')
}

/**
 * A function to convert hex string to Uint8Array
 * @deprecated use `arrayify` instead
 * @param hex hex string, e.g., '0x0102030405' or '0102030405'
 * @returns Uint8Array
 */
export function hexToBytes(hex: string): Uint8Array {
    return arrayify(hex)
}

/**
 * A function to trim the prefix 0x from a hex string
 * @param hex hex string
 * @returns hex string without 0x prefix
 */
export function trim0x(hex: string): string {
    return hex.replace(/^0x/i, '')
}

/**
 * A function to ensure the prefix 0x from a hex string
 * @param hex hex string
 * @returns hex string with 0x prefix
 */
export function ensure0x(hex: string): Hex {
    if (!isHex(hex)) {
        throw new Error('invalid hex string')
    }
    const value = trim0x(hex)
    const retval = `0x${value}`
    return retval as Hex
}

/**
 * A function to check if a string is a hex string
 * @deprecated use `isHex` instead
 * @param value
 * @returns
 */
export function isHexString(value: string): boolean {
    return isHex(value)
}

function _arrayify(value: string | number | Uint8Array | Buffer | bigint): Uint8Array {
    if (value instanceof Uint8Array) {
        return value
    }

    if (typeof value === 'string') {
        if (value.match(/^(0x)?[0-9A-F]*$/i)) {
            const hex = value.replace(/^0x/i, '')
            const len = hex.length + 1 - ((hex.length + 1) % 2)
            return Uint8Array.from(Buffer.from(hex.padStart(len, '0'), 'hex'))
        }
        throw new Error('Invalid hex string')
    }

    if (typeof value === 'number') {
        if (value < 0) {
            throw new Error('Number must be non-negative')
        }
        const byteArray = []
        while (value > 0) {
            byteArray.push(value & 0xff)
            value >>= 8
        }
        return new Uint8Array(byteArray.reverse())
    }

    if (typeof Buffer !== 'undefined' && Buffer.isBuffer(value)) {
        return new Uint8Array(value)
    }

    if (typeof value === 'bigint') {
        const hex = value.toString(16)
        return _arrayify(hex)
    }

    throw new Error('unsupported type')
}

/**
 * A function to convert a string|number|Uint8Array|Buffer|BigInt to Uint8Array
 * @param value - the value to convert
 * @param size - the size of the Uint8Array to return, if not specified, the size of the input will be returned
 */
export function arrayify(value: string | number | Uint8Array | Buffer | bigint, size?: number): Uint8Array {
    const bytes = _arrayify(value)
    if (size === undefined) {
        return bytes
    }
    return padify(bytes, { size })
}

/**
 * A function to convert a string|number|Uint8Array|Buffer|BigInt to hex string
 */
export function hexlify(value: string | number | Uint8Array | Buffer | bigint): Hex {
    if (typeof value === 'string' && /^(0x)?[0-9A-F]*$/i.test(value)) {
        const retval = '0x' + trim0x(value)
        return retval as Hex
    }

    const bytes = arrayify(value)
    const hex = Buffer.from(bytes).toString('hex')
    return ensure0x(hex)
}
