export function assert(condition: boolean, message?: string): asserts condition {
    if (!condition) {
        throw new Error(`Assertion Error:  ${message ?? 'condition is false'}`)
    }
}

/**
 * assertType
 * assertType can be used to assert that a value is of a certain type, and without naming a new variable explicitly.
 * @param value
 * @param fn
 * @param message
 */
export function assertType<T, M>(value: T, fn: (v: unknown) => v is M, message?: string): asserts value is T & M {
    if (!fn(value)) {
        throw new Error(`Expected value to be ${message ?? 'of correct type'}`)
    }
}

export function assertDefined<T>(value?: T, message?: string): asserts value is NonNullable<T> {
    if (value === undefined || value === null) {
        throw new Error(message ?? 'Value is undefined or null')
    }
}

export function asType<T, M>(value: T, fn: (v: unknown) => v is M, message?: string): M {
    if (!fn(value)) {
        throw new Error(`Expected value to be ${message ?? 'of correct type'}`)
    }
    return value
}

// eslint-disable-next-line @typescript-eslint/no-empty-function
export function assumeType<T>(value: unknown): asserts value is T {}
