import * as winston from 'winston'
import { Logger, format } from 'winston'

let logger: Logger | undefined = undefined

export { Logger }

function getStackTrace(): string | undefined {
    const oldLimit = Error.stackTraceLimit
    Error.stackTraceLimit = Infinity
    const retval = new Error().stack
    Error.stackTraceLimit = oldLimit
    return retval
}

// https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Errors/Cyclic_object_value
export function getCircularReplacer(): (key: string, value: unknown) => unknown {
    const ancestors: unknown[] = []
    return function (this: unknown, _key: string, value: unknown) {
        if (typeof value !== 'object' || value === null) {
            return value
        }
        // `this` is the object that value is contained in,
        // i.e., its direct parent.
        while (ancestors.length > 0 && ancestors.at(-1) !== this) {
            ancestors.pop()
        }
        if (ancestors.includes(value)) {
            return '[Circular]'
        }
        ancestors.push(value)
        return value
    }
}

function extractCallerInfo(line: string): string {
    for (const pattern of [/\((.*?:\d+:\d+)\)$/, /at (.*?:\d+:\d+)$/]) {
        const m = line.match(pattern)
        if (m === null) {
            continue
        }
        const [, fileInfoLine] = m
        return fileInfoLine
    }
    return '<unknown>'
}

const logFormat = format.printf(
    (info: {
        level: string
        message: string
        timestamp?: string
        metadata?: {
            pretty?: boolean
            format?: string
        }
    }) => {
        if (info.level.toUpperCase() !== 'ERROR' && info.level.toUpperCase() !== 'WARN') {
            return `${info.timestamp} ${info.level.toUpperCase()}: ${info.message}`
        }
        const stack = getStackTrace() ?? ''

        const stackLines = stack.split('\n')
        const index =
            stackLines.findIndex((line) => {
                return line.match(/create-logger.js/)
            }) + 1

        let fileInfo = '<unknown>'
        if (stackLines.length > index) {
            const line = stackLines[index]
            fileInfo = extractCallerInfo(line)
        }

        const formats: string[] = []
        if (fileInfo !== '<unknown>') {
            formats.push(fileInfo)
        }

        const { pretty, format } = info.metadata ?? {}
        const spaces = pretty === true ? 2 : undefined
        const value =
            typeof info.message === 'string'
                ? info.message
                : JSON.stringify(info.message, getCircularReplacer(), spaces)
        const message = format !== undefined ? format.replace(/%s/g, value) : value

        return [...formats, message].map((x) => `${info.timestamp} ${info.level.toUpperCase()}: ${x}`).join('\n')
    }
)

const loggerFormat = format.combine(
    format.timestamp({ format: 'YY-MM-DD HH:mm:ss' }),
    format.splat(),
    format.metadata({ fillExcept: ['level', 'timestamp', 'message'] }),
    logFormat,
    format.colorize({
        all: true,
    })
)

export function initLogger(level: string): void {
    if (!logger) {
        logger = createLogger(level)
    }
}

export function createLogger(level: string): Logger {
    const logger = winston.createLogger({
        level,
        format: loggerFormat,
        transports: [new winston.transports.Console()],
    })
    return logger
}

export function getLogger(): Logger {
    initLogger(process.env.LZ_LOG ?? 'info')
    if (!logger) {
        throw new Error('Logger is not initialized')
    }
    return logger
}

const exportsObject: {
    getCircularReplacer?: (key: unknown, value: unknown) => unknown
} = {}

if (process.env.NODE_ENV === 'test') {
    exportsObject.getCircularReplacer = getCircularReplacer
}
export default exportsObject
