import { ethers } from 'ethers'

import {
    Chain,
    EndpointId,
    EndpointVersion,
    Network,
    isNetworkEndpointIdSupported,
    networkToChain,
    networkToEndpointId,
} from '@layerzerolabs/lz-definitions'

export interface Deployment {
    /** Name of the contract deployment. */
    name: string

    /** Optional endpoint identifier. */
    compatibleVersions: EndpointVersion[]

    /** Network of deployment. */
    network: Network

    /** Optional contract source. */
    source?: string

    /** Address of deployed contract. */
    address: string

    /** Optional contract ABI. */
    abi?: string

    /** Optional contract bytecode. */
    bytecode?: string
}

/**
 * Find the matching deployments based on the given options
 * @todo Use Partial<EndpointSpec> instead of options
 * @param deployments list of deployments
 * @param nameOrAddress contract name
 * @param options options to match against
 * @returns Deployment
 */
export function findDeployment(
    deployments: Deployment[],
    nameOrAddress: string,
    options: { chain?: Chain; source?: string; network?: Network; endpointId?: EndpointId }
): Deployment {
    const retval = deployments.find((deployment) => {
        let hasMatchingNameOrAddress = deployment.name === nameOrAddress
        if (!hasMatchingNameOrAddress && ethers.utils.isAddress(nameOrAddress)) {
            hasMatchingNameOrAddress =
                ethers.utils.getAddress(deployment.address) === ethers.utils.getAddress(nameOrAddress)
        }
        const hasMatchingChain = options.chain == null || options.chain === networkToChain(deployment.network)
        const hasMatchingNetwork = options.network === undefined || options.network === deployment.network
        const hasMatchingSource = options.source === undefined || options.source === deployment.source
        let hasMatchingEndpoint = true
        if (options.endpointId != null) {
            const compatibleEndpoints = deployment.compatibleVersions.map((v) => {
                if (isNetworkEndpointIdSupported(deployment.network, v)) {
                    return networkToEndpointId(deployment.network, v)
                }
                return undefined
            })
            hasMatchingEndpoint = compatibleEndpoints.includes(options.endpointId)
        }
        return (
            hasMatchingNameOrAddress &&
            hasMatchingChain &&
            hasMatchingNetwork &&
            hasMatchingEndpoint &&
            hasMatchingSource
        )
    })

    if (retval === undefined) {
        throw new Error(`Deployment not found: ${nameOrAddress}`)
    }
    return retval
}

type ContractType = { [key in string]: ethers.Contract }
const contractCache: ContractType = {}
export function deploymentToEvmContract<T extends ethers.Contract>(
    deployment: Deployment,
    provider?: ethers.providers.Provider
): T {
    const key = `${deployment.network}-${deployment.address}`
    if (!(key in contractCache)) {
        if (deployment.abi === undefined || deployment.bytecode === undefined) {
            throw new Error('Deployment does not have ABI or bytecode')
        }
        const Contract = new ethers.ContractFactory(deployment.abi, deployment.bytecode)
        contractCache[key] = Contract.attach(deployment.address)
    }
    if (!provider) {
        return contractCache[key] as T
    }
    return contractCache[key].connect(provider) as T
}

export function findContract<T extends ethers.Contract>(
    provider: ethers.providers.Provider | undefined,
    deployments: Deployment[],
    nameOrAddress: string,
    options: { chain?: Chain; source?: string; network?: Network; endpointId?: EndpointId }
): T {
    const deployment = findDeployment(deployments, nameOrAddress, options)
    const retval = deploymentToEvmContract<T>(deployment, provider)
    return retval
}
